import base64, struct, zlib
def make_png(size):
    # Create a minimal orange PNG
    width = height = size
    raw = b''
    for y in range(height):
        raw += b'\x00'  # filter byte
        for x in range(width):
            # Simple orange square with hard hat shape
            if (x - width//2)**2 + (y - height//3)**2 < (width//3)**2:
                raw += b'\xff\x8c\x00\xff'  # orange
            elif height//2 < y < height*2//3 and width//4 < x < width*3//4:
                raw += b'\xff\x8c\x00\xff'  # orange
            else:
                raw += b'\x1b\x3a\x5c\xff'  # dark blue
    def chunk(ctype, data):
        c = ctype + data
        return struct.pack('>I', len(data)) + c + struct.pack('>I', zlib.crc32(c) & 0xffffffff)
    ihdr = struct.pack('>IIBBBBB', width, height, 8, 6, 0, 0, 0)
    return b'\x89PNG\r\n\x1a\n' + chunk(b'IHDR', ihdr) + chunk(b'IDAT', zlib.compress(raw)) + chunk(b'IEND', b'')
