    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file != null)
        {
            var buffer = new byte[file.Size];
            await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
            currentPhotoData = Convert.ToBase64String(buffer);
            currentCaption = string.Empty;
        }
    }

    private async Task SavePhoto()
    {
        if (currentPhotoData == null) return;
        var photo = new InspectionPhoto
        {
            FileName = $"photo_{DateTime.UtcNow:yyyyMMdd_HHmmss}.jpg",
            Base64Data = currentPhotoData,
            Caption = currentCaption,
            CapturedAt = DateTime.UtcNow
        };
        photos.Add(photo);
        currentPhotoData = null;
        currentCaption = string.Empty;
        await UpdateInspection();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        photos.Remove(photo);
        await UpdateInspection();
    }

    private async Task UpdateInspection()
    {
        if (inspection != null)
        {
            inspection.Photos = photos;
            await Storage.SaveInspectionAsync(inspection);
        }
    }

