using Microsoft.JSInterop;
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly IStorageService _storage;
    private readonly HttpClient _httpClient;
    private readonly IJSRuntime _jsRuntime;
    private IJSObjectReference? _module;
    private DotNetObjectReference<SyncService>? _dotNetRef;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; } = true;
    public int PendingCount { get; private set; }

    public SyncService(IStorageService storage, HttpClient httpClient, IJSRuntime jsRuntime)
    {
        _storage = storage;
        _httpClient = httpClient;
        _jsRuntime = jsRuntime;
    }

    public async Task InitializeAsync()
    {
        _module = await _jsRuntime.InvokeAsync<IJSObjectReference>("import", "./js/connectivity.js");
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _module.InvokeAsync<bool>("isOnline");
        await _module.InvokeVoidAsync("registerConnectivityHandler", _dotNetRef);
        await UpdatePendingCountAsync();
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        if (isOnline)
        {
            await SyncPendingAsync();
        }
        OnSyncStatusChanged?.Invoke();
    }

    public async Task SyncPendingAsync()
    {
        if (!IsOnline) return;

        var pending = await _storage.GetPendingSyncAsync();
        foreach (var inspection in pending)
        {
            try
            {
                var response = await _httpClient.PostAsJsonAsync("/api/inspections/sync", inspection);
                if (response.IsSuccessStatusCode)
                {
                    await _storage.MarkAsSyncedAsync(inspection.Id);
                }
            }
            catch
            {
                // Will retry on next sync
                break;
            }
        }
        await UpdatePendingCountAsync();
        OnSyncStatusChanged?.Invoke();
    }

    public async Task UpdatePendingCountAsync()
    {
        PendingCount = await _storage.GetPendingSyncCountAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            if (_dotNetRef is not null)
            {
                await _module.InvokeVoidAsync("unregisterConnectivityHandler");
            }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

export async function initialize() {
    if (db) return;
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event) => {
            const database = event.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (event) => {
            db = event.target.result;
            resolve();
        };
        request.onerror = (event) => reject(event.target.error);
    });
}

async function ensureDb() {
    if (!db) await initialize();
}

