        const tx = db.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const index = store.index('isSynced');
        const request = index.count(false);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

let handler = null;
let onlineCallback = null;
let offlineCallback = null;

export function isOnline() {
    return navigator.onLine;
}

export function registerConnectivityHandler(dotNetRef) {
    handler = dotNetRef;
    onlineCallback = () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true);
    offlineCallback = () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false);
    window.addEventListener('online', onlineCallback);
    window.addEventListener('offline', offlineCallback);
}

export function unregisterConnectivityHandler() {
    if (onlineCallback) window.removeEventListener('online', onlineCallback);
    if (offlineCallback) window.removeEventListener('offline', offlineCallback);
    handler = null;
    onlineCallback = null;
    offlineCallback = null;
}

