@page "/sites"
@inject IStorageService Storage

<PageTitle>Construction Sites</PageTitle>

<h2>🏢 Construction Sites</h2>

<div class="add-site-form card p-3 mb-4">
    <h5>Add New Site</h5>
    <div class="mb-2">
        <input type="text" class="form-control form-control-lg" placeholder="Site Name" @bind="newSiteName" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-lg" placeholder="Address" @bind="newSiteAddress" />
    </div>
    <button class="btn btn-primary btn-lg w-100" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(newSiteName)">
        ➕ Add Site
    </button>
</div>

@if (sites.Any())
{
    <div class="site-list">
        @foreach (var site in sites)
        {
            <div class="card mb-2 p-3 site-card">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">@site.Name</h5>
                        <small class="text-muted">@site.Address</small>
                    </div>
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => DeleteSite(site.Id)">🗑️</button>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted text-center mt-4">No sites added yet. Add your first construction site above.</p>
}

@code {
    private List<ConstructionSite> sites = new();
    private string newSiteName = string.Empty;
    private string newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Storage.InitializeAsync();
            sites = await Storage.GetSitesAsync();
        }
        catch { }
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(newSiteName)) return;
        var site = new ConstructionSite
        {
            Name = newSiteName,
            Address = newSiteAddress
        };
        await Storage.SaveSiteAsync(site);
        sites.Add(site);
        newSiteName = string.Empty;
        newSiteAddress = string.Empty;
    }

    private async Task DeleteSite(string id)
    {
        await Storage.DeleteSiteAsync(id);
        sites.RemoveAll(s => s.Id == id);
    }
}

@page "/new-inspection"
@inject IStorageService Storage
@inject NavigationManager Nav

<PageTitle>New Inspection</PageTitle>

<h2>➕ New Inspection</h2>

@if (!sites.Any())
{
    <div class="alert alert-info">
        <p>No construction sites found. Please <a href="sites">add a site</a> first.</p>
    </div>
}
else
{
    <div class="card p-3">
        <div class="mb-3">
            <label class="form-label fw-bold">Select Site</label>
            <select class="form-select form-select-lg" @bind="selectedSiteId">
                <option value="">-- Choose a site --</option>
                @foreach (var site in sites)
                {
                    <option value="@site.Id">@site.Name</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label fw-bold">Inspector Name</label>
            <input type="text" class="form-control form-control-lg" placeholder="Your name" @bind="inspectorName" />
        </div>

        <button class="btn btn-primary btn-lg w-100" @onclick="StartInspection"
                disabled="@(string.IsNullOrWhiteSpace(selectedSiteId) || string.IsNullOrWhiteSpace(inspectorName))">
            🚀 Start Inspection
        </button>
    </div>
}

@code {
    private List<ConstructionSite> sites = new();
    private string selectedSiteId = string.Empty;
    private string inspectorName = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Storage.InitializeAsync();
            sites = await Storage.GetSitesAsync();
        }
        catch { }
    }

    private void StartInspection()
    {
        if (string.IsNullOrWhiteSpace(selectedSiteId) || string.IsNullOrWhiteSpace(inspectorName)) return;
        Nav.NavigateTo($"/checklist/{selectedSiteId}/{Uri.EscapeDataString(inspectorName)}");
    }
}

@page "/checklist/{SiteId}/{InspectorName}"
@inject IStorageService Storage
@inject NavigationManager Nav

<PageTitle>Safety Checklist</PageTitle>

<h2>✅ Safety Checklist</h2>

@if (checklist.Any())
{
    <div class="checklist-progress mb-3">
        <div class="progress" style="height: 8px;">
            <div class="progress-bar bg-success" style="width: @PassPercent%"></div>
            <div class="progress-bar bg-danger" style="width: @FailPercent%"></div>
            <div class="progress-bar bg-secondary" style="width: @NaPercent%"></div>
        </div>
        <small class="text-muted">@CompletedCount / @checklist.Count completed</small>
    </div>

    @foreach (var category in checklist.GroupBy(c => c.Category))
    {
        <div class="category-section mb-3">
            <h5 class="category-header">@category.Key</h5>
            @foreach (var item in category)
            {
                <div class="checklist-item card p-2 mb-2 @GetItemClass(item)">
                    <div class="item-description mb-2">@item.Description</div>
