@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;
    [Parameter] public string InspectorName { get; set; } = string.Empty;

    private List<ChecklistItem> checklist = new();
    private string notes = string.Empty;
    private string inspectionId = Guid.NewGuid().ToString();

    private int CompletedCount => checklist.Count(c => c.Status != ChecklistStatus.NotChecked);
    private double PassPercent => checklist.Count > 0 ? (double)checklist.Count(c => c.Status == ChecklistStatus.Pass) / checklist.Count * 100 : 0;
    private double FailPercent => checklist.Count > 0 ? (double)checklist.Count(c => c.Status == ChecklistStatus.Fail) / checklist.Count * 100 : 0;
    private double NaPercent => checklist.Count > 0 ? (double)checklist.Count(c => c.Status == ChecklistStatus.NotApplicable) / checklist.Count * 100 : 0;

    protected override void OnInitialized()
    {
        checklist = GetDefaultChecklist();
    }

    private void SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = status;
    }

    private string GetItemClass(ChecklistItem item) => item.Status switch
    {
        ChecklistStatus.Pass => "border-success",
        ChecklistStatus.Fail => "border-danger",
        ChecklistStatus.NotApplicable => "border-secondary",
        _ => ""
    };

    private async Task SaveCurrentInspection()
    {
