+@page "/summary/{InspectionId}"
+@inject IStorageService Storage
+@inject SyncService SyncService
+@inject NavigationManager Nav
+
+<PageTitle>Inspection Summary</PageTitle>
+
+<h2>📋 Inspection Summary</h2>
+
+@if (inspection != null)
+{
+    <div class="card p-3 mb-3">
+        <h5>@siteName</h5>
+        <p class="text-muted mb-1">Inspector: @inspection.InspectorName</p>
+        <p class="text-muted mb-0">Date: @inspection.InspectedAt.ToString("g")</p>
+    </div>
+
+    <div class="summary-stats mb-3">
+        <div class="row text-center">
+            <div class="col-4">
+                <div class="stat-badge bg-success text-white p-2 rounded">
+                    <div class="fw-bold">@passCount</div>
+                    <small>Pass</small>
+                </div>
+            </div>
+            <div class="col-4">
+                <div class="stat-badge bg-danger text-white p-2 rounded">
+                    <div class="fw-bold">@failCount</div>
+                    <small>Fail</small>
+                </div>
+            </div>
+            <div class="col-4">
+                <div class="stat-badge bg-secondary text-white p-2 rounded">
+                    <div class="fw-bold">@naCount</div>
+                    <small>N/A</small>
+                </div>
+            </div>
+        </div>
+    </div>
+
+    @if (failures.Any())
+    {
+        <div class="card p-3 mb-3 border-danger">
+            <h6 class="text-danger">⚠️ Failures (@failures.Count)</h6>
+            @foreach (var item in failures)
+            {
+                <div class="mb-1">
+                    <strong>@item.Category:</strong> @item.Description
+                    @if (!string.IsNullOrEmpty(item.Comment))
+                    {
+                        <br /><small class="text-muted">Note: @item.Comment</small>
+                    }
+                </div>
+            }
+        </div>
+    }
+
+    @if (!string.IsNullOrWhiteSpace(inspection.Notes))
+    {
+        <div class="card p-3 mb-3">
+            <h6>📝 Notes</h6>
+            <p>@inspection.Notes</p>
+        </div>
+    }
+
+    @if (inspection.Photos.Any())
+    {
+        <div class="card p-3 mb-3">
+            <h6>📷 Photos (@inspection.Photos.Count)</h6>
+            @foreach (var photo in inspection.Photos)
+            {
+                <div class="mb-2">
+                    <img src="@($"data:image/jpeg;base64,{photo.Base64Data}")" class="img-fluid rounded" style="max-height: 100px;" />
+                    @if (!string.IsNullOrEmpty(photo.Caption))
+                    {
+                        <br /><small>@photo.Caption</small>
+                    }
+                </div>
+            }
+        </div>
+    }
+
+    <div class="d-grid gap-2 mb-4">
+        @if (!isSaved)
+        {
+            <button class="btn btn-success btn-lg" @onclick="SaveInspection">
+                💾 Save Inspection
+            </button>
+            <button class="btn btn-outline-primary btn-lg" @onclick="GoBackToChecklist">
+                ← Edit Checklist
+            </button>
+        }
+        else
+        {
+            <div class="alert alert-success text-center">
+                ✅ Inspection saved successfully!
+                @if (!inspection.IsSynced)
+                {
+                    <br /><small>Will sync when online.</small>
+                }
+            </div>
+            <button class="btn btn-primary btn-lg" @onclick="GoHome">
+                🏠 Back to Home
+            </button>
+        }
+    </div>
+}
+else
+{
+    <p>Loading inspection...</p>
+}
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = string.Empty;
+
+    private Inspection? inspection;
+    private string siteName = string.Empty;
+    private int passCount, failCount, naCount;
+    private List<ChecklistItem> failures = new();
+    private bool isSaved;
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            await Storage.InitializeAsync();
+            inspection = await Storage.GetInspectionAsync(InspectionId);
+            if (inspection != null)
+            {
+                var site = await Storage.GetSiteAsync(inspection.SiteId);
+                siteName = site?.Name ?? "Unknown Site";
+                passCount = inspection.Checklist.Count(c => c.Status == ChecklistStatus.Pass);
+                failCount = inspection.Checklist.Count(c => c.Status == ChecklistStatus.Fail);
+                naCount = inspection.Checklist.Count(c => c.Status == ChecklistStatus.NotApplicable);
+                failures = inspection.Checklist.Where(c => c.Status == ChecklistStatus.Fail).ToList();
+            }
+        }
+        catch { }
+    }
+
+    private async Task SaveInspection()
+    {
+        if (inspection == null) return;
+        inspection.IsSynced = false;
+        await Storage.SaveInspectionAsync(inspection);
+        isSaved = true;
+
+        if (SyncService.IsOnline)
+        {
+            await SyncService.SyncPendingAsync();
+        }
+        await SyncService.UpdatePendingCountAsync();
+    }
+
+    private void GoBackToChecklist()
+    {
+        if (inspection != null)
+            Nav.NavigateTo($"/checklist/{inspection.SiteId}/{Uri.EscapeDataString(inspection.InspectorName)}");
+    }
+
+    private void GoHome()
+    {
+        Nav.NavigateTo("/");
+    }
+}
