@page "/"
@inject IStorageService Storage
@inject SyncService SyncService

<PageTitle>Site Inspector - Home</PageTitle>

<div class="dashboard">
    <h1>🏗️ Site Inspector</h1>
    <p class="lead">Construction Safety Inspection App</p>

    <div class="stats-grid">
        <div class="stat-card">
            <div class="stat-number">@siteCount</div>
            <div class="stat-label">Sites</div>
        </div>
        <div class="stat-card">
            <div class="stat-number">@inspectionCount</div>
            <div class="stat-label">Inspections</div>
        </div>
        <div class="stat-card @(pendingCount > 0 ? "pending" : "")">
            <div class="stat-number">@pendingCount</div>
            <div class="stat-label">Pending Sync</div>
        </div>
    </div>

    <div class="quick-actions">
        <a href="new-inspection" class="btn btn-primary btn-lg btn-action">
            ➕ New Inspection
        </a>
        <a href="sites" class="btn btn-outline-primary btn-lg btn-action">
            🏢 Manage Sites
        </a>
        <a href="history" class="btn btn-outline-secondary btn-lg btn-action">
            📋 View History
        </a>
    </div>

    @if (pendingCount > 0 && SyncService.IsOnline)
    {
        <button class="btn btn-warning btn-lg mt-3" @onclick="SyncNow">
            🔄 Sync Now (@pendingCount items)
        </button>
    }
</div>

@code {
    private int siteCount;
    private int inspectionCount;
    private int pendingCount;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Storage.InitializeAsync();
            var sites = await Storage.GetSitesAsync();
            siteCount = sites.Count;
            var inspections = await Storage.GetInspectionsAsync();
            inspectionCount = inspections.Count;
            pendingCount = await Storage.GetPendingSyncCountAsync();
        }
        catch { }
    }

    private async Task SyncNow()
    {
        await SyncService.SyncPendingAsync();
        pendingCount = await Storage.GetPendingSyncCountAsync();
    }
}

