html, body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    -webkit-tap-highlight-color: transparent;
}

/* Mobile-first layout */
.page {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

@media (min-width: 769px) {
    .page {
        flex-direction: row;
    }
}

main {
    flex: 1;
}

.content {
    padding-top: 1rem;
}

/* Touch targets */
.btn-lg, .form-control-lg, .form-select-lg {
    min-height: 48px;
    font-size: 1.1rem;
}

/* Dashboard */
.dashboard {
    text-align: center;
    padding: 1rem 0;
}

.stats-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 0.75rem;
    margin: 1.5rem 0;
}

.stat-card {
    background: #f8f9fa;
    border-radius: 12px;
    padding: 1rem;
    text-align: center;
}

.stat-card.pending {
    background: #fff3cd;
}

.stat-number {
    font-size: 2rem;
    font-weight: bold;
    color: #333;
}

.stat-label {
    font-size: 0.8rem;
    color: #666;
    text-transform: uppercase;
}

/* Quick actions */
.quick-actions {
    display: grid;
    gap: 0.75rem;
}

.btn-action {
    padding: 1rem;
    font-size: 1.1rem;
}

/* Checklist */
.category-header {
    background: #e9ecef;
    padding: 0.5rem 1rem;
    border-radius: 8px;
    margin-bottom: 0.5rem;
    font-weight: 600;
}

.checklist-item {
    border-left: 4px solid #dee2e6;
}

.checklist-item.border-success {
    border-left-color: #198754 !important;
    background: #f0fff4;
}

.checklist-item.border-danger {
    border-left-color: #dc3545 !important;
    background: #fff5f5;
}

.checklist-item.border-secondary {
    border-left-color: #6c757d !important;
    background: #f8f9fa;
}

.item-description {
    font-weight: 500;
    font-size: 0.95rem;
}

.btn-checklist {
    min-height: 48px;
    font-weight: 600;
    font-size: 1rem;
}

/* Cards */
.site-card, .inspection-history-card {
    cursor: pointer;
    transition: transform 0.1s;
}

.site-card:active, .inspection-history-card:active {
    transform: scale(0.98);
}

/* Sync status */
.sync-status {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

/* Photo capture */
.photo-capture label {
    cursor: pointer;
    display: block;
}

/* Progress bar */
.checklist-progress .progress {
    border-radius: 4px;
}

/* Top row */
.top-row {
    height: 3.5rem;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    border-bottom: 1px solid #e5e5e5;
}

/* Sidebar styles */
.sidebar {
    background: linear-gradient(180deg, #1b3a5c 0%, #0f2942 100%);
}

.navbar-brand {
    font-size: 1.1rem;
}

/* Error UI */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

.valid.modified:not([type=checkbox]) {
    outline: 1px solid #26b050;
}

.invalid {
    outline: 1px solid #e50000;
}

.validation-message {
    color: #e50000;
}

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
    }

